// llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
// Helper function to determine if the VPlan-native path includes additional
// simplifications that are not included in the legacy cost model.
static bool planContainsAdditionalSimplifications(
    VPlanPtr &Plan, LoopVectorizeCost-Context &CostCtx, Loop *OrigLoop) {
  // The VPlan-native path performs LICM of instructions with loop-invariant
  // operands. Check if the plan contains any such instructions.
  for (auto &R : Plan->getRoots()) {
    for (VPInstruction *VPI : R->getVPInstructions())
      if (auto *VPV = dyn_cast<VPValue>(VPI))
        if (auto *I = dyn_cast_or_null<Instruction>(VPV->getUnderlyingValue()))
          if (OrigLoop->isLoopInvariant(I->getOperand(0)) &&
              (I->getNumOperands() == 1 ||
               OrigLoop->isLoopInvariant(I->getOperand(1))))
            return true;
  }

  return false;
}
```

This checks for LICM of instructions with loop invariant operands.

